#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int n,maxn,q;
int l[240005],r[240005],sum[240005],tag[240005];
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
inline int f(int x,int y)
{
	return x>y?x:y;
}
void build(int id,int lt,int rt)//建树
{
	l[id]=lt,r[id]=rt;
	int mid=(lt+rt)>>1;
	if(lt==rt)
	{
		return;
	}
	int ls=id*2,rs=id*2+1;
	build(ls,lt,mid);
	build(rs,mid+1,rt);
}
inline void ad(int id,int v)
{
	tag[id]+=v;
	sum[id]+=v;
}
inline void pd(int id)//pushdown
{
	int ls=id*2,rs=id*2+1;
	ad(ls,tag[id]);
	ad(rs,tag[id]);
	tag[id]=0;
}
void upd(int id,int x,int y,int v)//区间修改
{
	if(x<=l[id]&&y>=r[id])
	{
		ad(id,v);//加
		return;
	}
	pd(id);
	int ls=id*2,rs=id*2+1;
	if(x<=r[ls])
	{
		upd(ls,x,y,v);
	}
	if(y>=l[rs])
	{
		upd(rs,x,y,v);
	}
	sum[id]=f(sum[ls],sum[rs]);
}
int query(int id,int x,int y)//查询最大值
{
	if(x<=l[id]&&y>=r[id])
	{
		return sum[id];
	}
	int res=0;
	pd(id);
	int ls=id*2,rs=id*2+1;
	if(x<=r[ls])
	{
		res=f(res,query(ls,x,y));
	}
	if(y>=l[rs])
	{
		res=f(res,query(rs,x,y));
	}
	return res;
}
signed main(void)
{
	IOS
	cin>>n>>maxn>>q;
	build(1,1,n);
	int x,y,v;
	wh(q--)
	{
		cin>>x>>y>>v;
		y--;
		if(query(1,x,y)+v>maxn)
		{
			cout<<"N\n";
		}
		else
		{
			cout<<"T\n";
			upd(1,x,y,v);
		}
	}
	return 0;
}
